import java.io.*;class WriteAFile extends FileOutputStream {		private int lastDigit;		public WriteAFile(String directory, String fileName) throws FileNotFoundException{		super(directory+fileName);		lastDigit = -1;	}		public void writeMe(String arg) throws IOException{				for(int i=0; i<arg.length(); i++) {			write((int) arg.charAt(i) );		}		write(13);		lastDigit = 13;	}		public void writeMe(int intVal) throws IOException {		String s = Integer.toString(intVal);				for(int i=0; i<s.length(); i++)			write( (int)(    s.charAt(i)   )   );		lastDigit = (int)s.charAt(s.length()-1);	}		public void writeMe(float floatVal) throws IOException {		String s = Float.toString(floatVal);				for(int i=0; i<s.length(); i++)			write( (int)(    s.charAt(i)   )   );		lastDigit = (int)s.charAt(s.length()-1);	}			}